import React, { useEffect, useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import apiClient from '../api/axios';

function Sidebar({ isOpen, onToggle, onMenuSelect }) {
  const [menus, setMenus] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    fetchMenus();
  }, []);

  const fetchMenus = async () => {
    try {
      setLoading(true);
      const response = await apiClient.get('/v3/menus', {
        params: {
          'parent_id': import.meta.env.VITE_PARENT_ID,
          'project-id': import.meta.env.VITE_PROJECT_ID,
        },
      });
      const menuData = response?.data?.data?.menus ?? [];
      setMenus(menuData);
    } catch (error) {
      console.error('Failed to fetch menus:', error);
      setMenus([]);
    } finally {
      setLoading(false);
    }
  };

  const handleMenuClick = (item) => {
    if (item.type === 'TABLE' && item.data?.table?.slug) {
      const slug = item.data.table.slug;
      navigate(`/tables/${slug}`, { state: { menuLabel: item.label } });
      onMenuSelect?.(item);
    }
  };

  const isActive = (item) => {
    if (item.type === 'TABLE' && item.data?.table?.slug) {
      return location.pathname === `/tables/${item.data.table.slug}`;
    }
    return false;
  };

  return (
    <div
      id="main-sidebar"
      className="flex flex-col transition-all duration-300 ease-in-out"
      style={{
        width: isOpen ? '240px' : '0px',
        minWidth: isOpen ? '240px' : '0px',
        backgroundColor: '#1F2937',
        borderRight: `1px solid rgba(0, 0, 0, 0.3)`,
        overflow: isOpen ? 'visible' : 'hidden',
      }}
    >
      <div
        className="flex items-center justify-between px-4 flex-shrink-0"
        style={{
          height: '56px',
          borderBottom: `1px solid rgba(0, 0, 0, 0.3)`,
          overflow: 'visible',
        }}
      >
        <div
          className="font-semibold text-base transition-opacity duration-300"
          style={{
            color: '#F9FAFB',
            opacity: isOpen ? 1 : 0,
          }}
        >
          ERP Admin
        </div>
        <button
          onClick={onToggle}
          className="flex items-center justify-center rounded-full transition-all duration-200"
          style={{
            width: '25px',
            height: '25px',
            backgroundColor: 'rgba(255, 255, 255, 0.1)',
            border: `1px solid rgba(255, 255, 255, 0.2)`,
            color: '#F9FAFB',
            cursor: 'pointer',
            position: 'relative',
            right: '-12.5px',
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.backgroundColor = 'rgba(255, 255, 255, 0.15)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.backgroundColor = 'rgba(255, 255, 255, 0.1)';
          }}
        >
          <span style={{ fontSize: '12px' }}>{isOpen ? '‹' : '›'}</span>
        </button>
      </div>

      <div
        className="flex-1 transition-opacity duration-300"
        style={{
          overflowY: isOpen ? 'auto' : 'hidden',
          overflowX: 'hidden',
          opacity: isOpen ? 1 : 0,
        }}
      >
        {loading ? (
          <div className="p-4" style={{ color: 'rgba(249, 250, 251, 0.5)' }}>
            Loading menus...
          </div>
        ) : (
          <nav className="py-2">
            {menus.map((item) => {
              const icon = item.icon || '📁';
              const active = isActive(item);

              return (
                <button
                  key={item.guid}
                  onClick={() => handleMenuClick(item)}
                  className="w-full flex items-center px-4 py-2 text-left transition-colors duration-150"
                  style={{
                    backgroundColor: active ? 'rgba(59, 130, 246, 0.3)' : 'transparent',
                    color: active ? '#60A5FA' : '#D1D5DB',
                    border: 'none',
                    cursor: 'pointer',
                  }}
                  onMouseEnter={(e) => {
                    if (!active) {
                      e.currentTarget.style.backgroundColor = 'rgba(255, 255, 255, 0.08)';
                      e.currentTarget.style.color = '#F9FAFB';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (!active) {
                      e.currentTarget.style.backgroundColor = 'transparent';
                      e.currentTarget.style.color = '#D1D5DB';
                    }
                  }}
                >
                  <span className="mr-2" style={{ fontSize: '16px' }}>
                    {icon}
                  </span>
                  <span style={{ fontSize: '14px' }}>{item.label}</span>
                </button>
              );
            })}
          </nav>
        )}
      </div>
    </div>
  );
}

export default Sidebar;
